var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"헉…… 허억……","JPN":"はぁ……はぁ……","ENG":"*Pant*","TWN":"咳……咳咳……"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"후후, 이렇게나 간단한 것을 굳이 어렵게 갈 필요는 없지.","JPN":"ふふ、こんな簡単なことをあえて難しくやる必要はない。","ENG":"Yes, it’s so simple.","TWN":"呵呵，事情明明很簡單，有必要搞成這樣嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L5_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"어떠냐? 인간이라면 탐낼 법도 한 힘이지?","JPN":"どうだ？　人間なら欲しがる力だろう？","ENG":"What do you say? This certainly is a power that any human would covet, don’t you agree?","TWN":"如何？這是人類很想要的力量吧？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"당주님께는…… 갈 수 없다.","JPN":"当主には……近づかせない。","ENG":"I will not let you hurt... my Lady...","TWN":"不可以……去找堂主。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유!","JPN":"千冬！","ENG":"Chifuyu!","TWN":"千冬！"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"주제를 모르고 내 발목을 잡다니.","JPN":"身の程知らずが我の足を掴むとは。","ENG":"How dare you touch me.","TWN":"也不掂掂自己幾兩重，竟敢攔我！"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"얌전히 죽어가면서 기다리고 있거라. 곧 그 몸에서 예쁜 구슬을 뽑아줄 테니.","JPN":"大人しく死にながら待っていなさい。\\nすぐその体から綺麗な玉を抜き取ってやる。","ENG":"Stay here and wait for me. I’ll be back to make a pretty orb out of you.","TWN":"乖乖的去死後等我，我很快就會從你身上取出漂亮的珠子。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"안 돼……","JPN":"いけない……","ENG":"No...","TWN":"不可以……"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"이젠 정말 버티기가……","JPN":"これ以上は持ちこたえることが……","ENG":"I can’t stand it anymore...","TWN":"我真的撐不……"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"뭐지? 가면에서…… 빛이?","JPN":"なに？　お面から……光が？","ENG":"What’s this? The mask... It’s shining!","TWN":"什麼？面具裡有……光？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"하아…… 하아……","JPN":"はあ……はあ……","ENG":"*Pant*","TWN":"呼呼……呼呼……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"찾아라! 멀리 가지 못했다!","JPN":"探せ！　遠くまでは逃げていないはずだ！","ENG":"Find her! She won’t be far!","TWN":"快找！應該沒跑遠！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_MASKED","text":{"KOREA":"당주님은, 여기 숨어 계십시오.","JPN":"ご当主様はここに隠れていてください。","ENG":"Stay here, Lady.","TWN":"堂主，您就躲在這裡。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_MASKED","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_MASKED","text":{"KOREA":"제가 배반자들을 처리하겠습니다.","JPN":"私が裏切り者を始末します。","ENG":"I’ll go take care of the betrayers.","TWN":"我去解決叛徒。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"카나데…… 미안하다.","JPN":"かなで……すまない。","ENG":"Kanade... I’m sorry.","TWN":"速水奏……對不起。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"난 이젠 틀린 것 같구나.","JPN":"私はもう無理なようだ。","ENG":"I don’t think I can go any further.","TWN":"都怪我不好。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"그런 말씀 마십시오.","JPN":"そんなことをおっしゃらないでください。","ENG":"Don’t say that.","TWN":"您別這麼說。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"따돌릴 방법이 있을 겁니다.","JPN":"追っ手を引き離せる方法があるはずです。","ENG":"There must be a way out of here.","TWN":"應該有辦法可以甩掉他們。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"그런 뒤엔 곧바로 병원을……","JPN":"その後はすぐに病院へ……","ENG":"Then we’ll go find a doctor...","TWN":"然後我們再去去醫院……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"카나데.","JPN":"かなで。","ENG":"Kanade.","TWN":"速水奏。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"내가 잡히면…… 난 오로치를 깨우는 제물로 쓰이게 될 거다.","JPN":"私が捕まれば……私はオロチを起こすための供物として\\n使われることになる。","ENG":"If they catch me, they will sacrifice me to wake Orochi.","TWN":"我被抓到的話……就會成為喚醒大蛇的祭物。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니, 그렇게 되기 전에 나를……","JPN":"だから、そうなる前に私を……","ENG":"Before that happens, you have to...","TWN":"與其這樣，那不如現在就把我……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"여기에 계셨군요, 당주.","JPN":"こちらにいましたか、ご当主。","ENG":"There you are, Lady Nanahara.","TWN":"原來您在這裡，堂主。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"찾고 있었습니다.","JPN":"探しましたよ。","ENG":"We’ve been looking for you.","TWN":"我們一直在找您呢。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"사요! 네가 감히, 당주님을 배반하다니!","JPN":"小夜！　貴様がご当主様を裏切るとは！","ENG":"Sayo! You dare betray Lady Nanahara!","TWN":"小夜！你敢背叛堂主！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"뭔가 사소한 오해가 있는 것 같군요.","JPN":"どうやら少し誤解があるようですね。","ENG":"There must be a misunderstanding.","TWN":"好像有什麼誤會。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"목장의 돼지는 원래 자신의 역할을 몰라도 된답니다.","JPN":"養豚場の豚は本来、自分の役割を知らなくてもいいものです。","ENG":"A pig in a farm doesn’t have to know the role it serves.","TWN":"豬圈裡的豬本來就不需要知道自己的作用。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"주인이 그 사실을 알려주지 않았다고 해서 배반이라 부르진 않지요.","JPN":"飼い主がその事実を教えてくれなかったからといって、\\n裏切りとは呼ばないでしょう。","ENG":"And I wouldn't call the farmer a betrayer just because he didn’t tell the pig what will happen to it.","TWN":"主人沒公開這個事實，就不算是背叛。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"뭐, 돼지의 분함은 동정할 수는 있겠지만…… 이건 어디까지나 순리이니까요.","JPN":"まあ、豚の悔しさに同情することはできますが……\\nこれはあくまでも道理ですからね。","ENG":"You may feel sorry for the pig... but this is the way of nature.","TWN":"雖然可以同情豬的憤怒… 也算是人之常情。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_PRIDE"}}}},{"id":"L3_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"뻔뻔하구나.","JPN":"図々しいやつめ。","ENG":"You have no shame.","TWN":"你真是厚顏無恥！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_PRIDE"}}}},{"id":"L4_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"그만 비켜 주시겠습니까? 당주께서 많이 괴로워하시는 것 같은데, 저희가 모시지요.","JPN":"そろそろ退いていただけますか？　\\nご当主がかなり苦しんでおられるようですので、私たちがお付き添いいたします。","ENG":"Could you please stand back? Lady Nanahara is obviously in great pain. Let us take care of her.","TWN":"麻煩讓一讓好嗎？堂主似乎很痛苦，讓我們來侍候吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_PAST","text":{"KOREA":"그럼, 제가 모시도록 하지요.","JPN":"では、ここからは我々にお任せください。","ENG":"Let me help.","TWN":"還是我來伺候吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_PAST","text":{"KOREA":"쿠와아앗! ……내 어, 얼굴이!","JPN":"グアッ！　……か、顔が！！","ENG":"Urgh! My face!","TWN":"呃啊啊！……我的臉！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"물러서라. 당주님께 손을 대는 자는 용서치 않겠다.","JPN":"下がれ。ご当主様に触れるものは容赦せぬ。","ENG":"Stand back. Do not touch Lady Nanahara.","TWN":"退下！敢對堂主下手，休怪我手下不留情。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"크윽?! 어째서 갑자기 몸이……?","JPN":"くっ！？　急に体が……？","ENG":"Khhk? What’s happening to my body?","TWN":"咳咳？！身體怎麼突然……？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"후후, 이제야 독이 듣는 모양이군요.","JPN":"ふふ、やっと毒が効いてきたようですね。","ENG":"Finally, the poison is working.","TWN":"呵呵，藥效終於發作了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"무사님이 평소 즐기시는 찻잎에 티 나지 않게 섞어 넣었답니다.","JPN":"そなたが普段好んでいる茶葉にわからぬように混ぜておきました。","ENG":"I mixed some poison in with your tea leaves.","TWN":"我在你平時愛喝的茶裡，加了點毒藥。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"따님도 같이 드시지 않았다면 좋겠군요.","JPN":"娘は一緒に飲んでいないといいですね。","ENG":"I hope you didn’t enjoy it with your daughter.","TWN":"希望你女兒沒有和你一起喝那杯茶。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"뭣들 하고 있니? 당주가 죽으면 피도 쓸모 없어지니 어서 움직이거라.","JPN":"さあ、何をしておる！　当主が死ねば血は無駄になる。さっさと動け。","ENG":"What are you doing? We need her alive, move!","TWN":"愣著幹嘛？堂主要是死了血就沒用了，動作快！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"옛!","JPN":"はっ！","ENG":"Yes, ma’am!","TWN":"遵命！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"이 놈","JPN":"貴様","ENG":"Y-you...","TWN":"你們"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"들……!","JPN":"ら……！","ENG":"dare...","TWN":"這些傢伙…！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"카나데……","JPN":"かなで……","ENG":"Kanade...","TWN":"速水奏……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"부탁한다.","JPN":"頼む。","ENG":"Please.","TWN":"拜託你。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"죄송합니다, 당주님.","JPN":"申し訳ございません、ご当主様。","ENG":"I’m sorry, Lady Nanahara.","TWN":"對不起，堂主。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"당주님께서 제단으로 가려고 하셨을 때 제가 막지 않았다면, 적어도 이런 꼴은 당하시지 않았을 텐데……","JPN":"当主様が祭壇に行かれようとした時に私が止めなかったら、\\n少なくともこんな目にはあわなかったはず……","ENG":"I shouldn’t have stopped you when you were going to the altar.","TWN":"堂主要去祭壇時，若不是我攔著您，也不會害您變成現在這樣…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"카나데…….","JPN":"かなで……","ENG":"Kanade...","TWN":"速水奏……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"실은 나도 알고 있었단다.","JPN":"実は私も知っていたのだ。","ENG":"I already knew...","TWN":"其實我也很清楚。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"네가 제단으로 가는 날 막으러 올 것이라고 말이야.","JPN":"祭壇に向かう私を君が止めに来るということを。","ENG":"... that you were going to stop me from going to the altar.","TWN":"你會來攔著我，不讓我去祭壇。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"나도… 천총운검에 목숨을 바치는 걸 망설였어.","JPN":"私も……天叢雲剣に命を捧げることをためらっていた。","ENG":"I hesitated to sacrifice myself with Kusanagi.","TWN":"我其實…也很猶豫要把我的性命獻給天叢雲劍嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"너와 내 아이들과 작별해야 한다는 게 싫었어.","JPN":"君や私の子どもたちと別れなければならないのが嫌だった。","ENG":"I didn’t want to leave you and my children behind.","TWN":"因為我不想與你和我的孩子道別。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"그래서 함께 도망치고 싶었는데…","JPN":"だから一緒に逃げたかったのだが……","ENG":"So I wanted to run away with you...","TWN":"所以原本打算要一起逃走…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"더는 바람의 목소리가 길을 가르쳐주지 않더구나.","JPN":"これ以上は風の声が道を教えてくれなかった。","ENG":"But then the voice of wind stopped whispering to me.","TWN":"但風聲卻再不指引我方向。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"결국 이렇게 됐지만… 난 널 원망하지 않아.","JPN":"結局こうなってしまったが……私は君を恨まない。","ENG":"It’s come down to this... but I don’t resent you.","TWN":"雖然結果是這樣…但我不恨你。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니… 마지막만큼은 내 부탁을 들어다오.","JPN":"だから……最期だけは私の頼みを聞いてくれ。","ENG":"So please... grant me my last wish...","TWN":"所以…請你聽我最後的請求。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"당주님…….","JPN":"ご当主様……","ENG":"Lady…","TWN":"堂主……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"저를, 용서하지 마십시오.","JPN":"どうか、私を許さないでくださいませ。","ENG":"Please don’t forgive me...","TWN":"請不要原諒我。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"무, 무슨 짓이냐!","JPN":"な、何の真似だ！","ENG":"W-what are you doing?","TWN":"你…你在幹什麼！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"호위 무사가 당주를 죽이다니!","JPN":"護衛が当主を殺すなんて！","ENG":"How can a bodyguard kill her own Lady?","TWN":"護衛武士竟然殺死堂主！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"곧 코앞이었는데……","JPN":"あと少しだったのに……","ENG":"I was almost there...","TWN":"就差一步……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"오로치님의 힘이 없으면 이 몸으론 얼마나 더 갈지도 모르는데, 잘도 이런 짓을……!","JPN":"オロチ様の力がなければこの体がどれほど持つかわからないのに、\\nよくもそんなことを……！","ENG":"I don’t know how long I’ll last without Lord Orochi’s power... How dare you!","TWN":"如果沒有大蛇的力量，我這個身體不知道還能撐到什麼時候，竟然……！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"사요, 네 어리석음은 결국 자멸을 부를 거다.","JPN":"小夜、貴様のその愚かさは最期に自滅を招くだろう。","ENG":"Sayo, your foolishness will be your downfall.","TWN":"小夜，你的愚蠢終究會自取滅亡。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"닥쳐!","JPN":"黙れ！","ENG":"Shut up!","TWN":"閉嘴！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"네 년은 내 손으로 죽여주마!","JPN":"貴様は私の手で殺してやる！","ENG":"I will kill you myself!","TWN":"我要親自殺了你！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"헉…… 헉……","JPN":"はぁ……はぁ……","ENG":"*Pant*","TWN":"呼……呼……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_PAST","text":{"KOREA":"크흠…… 이 정도면 확실하게 죽었군.","JPN":"ふむ……これなら間違いなく死んだな。","ENG":"Ahem... She’s dead.","TWN":"咳咳……這樣應該是死了吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_PAST","text":{"KOREA":"직계 무녀가 죽었으니, 자식이라도 바쳐야하나? 병약하긴 해도 일단은 무녀 혈통이니까……","JPN":"直系の巫女が死んだし、その子どもでも捧げるべきか？\\n病弱ではあるが一応巫女の血統だから……","ENG":"Since the priestess is gone now, maybe we should sacrifice her daughter. She is sickly, but she is of the same blood.","TWN":"既然直系巫女死了，那要獻她的後裔嗎？雖然體弱多病，但起碼是巫女的血統……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"성급하게 굴면 인과가 뒤틀릴 뿐입니다. 때가 되면 오로치님께서 저에게 속삭이실 테니 기다리십시오.","JPN":"性急に行動しても因果が歪むだけです。\\n時がくればオロチ様が私にささやいてくださるので、その時を待ちましょう。","ENG":"Don’t rush. It will only bring more distortion to our destined future. Lord Orochi will speak to me when the time comes.","TWN":"欲速則不達，等時機成熟時大蛇跟我說的，請耐心等候。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_PAST","text":{"KOREA":"그렇다면 지금 당장은 오로치님을 깨우기 어렵겠군.","JPN":"ならば今すぐオロチ様を呼び起こすのは難しそうだな。","ENG":"Well then, I suppose we can’t wake Lord Orochi for now.","TWN":"那現在應該無法喚醒大蛇。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_PAST","text":{"KOREA":"본부에는 뭐라고 둘러대야 하지?","JPN":"本部には何と言い訳するのだ？","ENG":"What do we tell headquarters?","TWN":"該怎麼跟總部解釋才好呢？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"보면 모르겠습니까? 이 호위 무사 년이 당주를 죽이고 도망친 겁니다.","JPN":"考えるまでもありません。この護衛が当主を殺して逃げたのです。","ENG":"Can’t you see? The bodyguard killed Lady Nanahara and ran away.","TWN":"不是很明顯嗎？護衛武士殺了堂主後逃了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_PAST","text":{"KOREA":"아아, 그렇지. 그렇게 되는 것이지.","JPN":"ああ、そうか。そういうことになるな。","ENG":"Oh, yes, yes. That’s right.","TWN":"對對，沒錯，就是這麼回事。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_PAST","text":{"KOREA":"그럼 호위 무사는 어떻게 처리한다?","JPN":"では護衛の死体はどうする？","ENG":"What do we do with the dead bodyguard?","TWN":"那護衛武士要怎麼處理？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"적당한 곳에 버리십시오.","JPN":"適当なところに捨ててください。","ENG":"Bury her.","TWN":"找個適合的地方扔了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"오로치님이 봉인된 산에 묻으면 충분할 겁니다.","JPN":"オロチ様が封印された山に埋めればいいでしょう。","ENG":"Anywhere on this mountain where Lord Orochi is sealed.","TWN":"就埋在封印大蛇的山上裡吧！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"누구도 함부로 발길을 들이지 않는 곳이니까요.","JPN":"誰も安易に足を踏み入れない場所ですから。","ENG":"No one will dare come here.","TWN":"畢竟那個地方不是誰都可以靠近的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"그리고 당주께선, 돌아가기 전에 그 흉한 얼굴부터 가리는 편이 좋겠군요.","JPN":"それと当主は、戻る前にその酷い顔を隠したほうがよいでしょう。","ENG":"And I suggest you hide that scar on your face.","TWN":"還有，堂主回去前，最好先遮住你那張醜陋的臉。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"이건…… 하야미 카나데의 기억.","JPN":"これは……速水かなでの記憶。","ENG":"This is... Hayami Kanade’s memory.","TWN":"這是……速水奏的記憶。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"후후훗, 재미있는 물건을 찾았구나?","JPN":"ふふふ、面白いものを見つけたな？","ENG":"Hah hah, you found an interesting toy.","TWN":"呵呵呵，你找到有趣的東西了？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"감상은 어떠니? 그것이 인간의 추악한 이기심이 낳은 참극이란다.","JPN":"どう思う？　それは人間の醜悪な利己主義が生んだ惨劇だ。","ENG":"What do you think? That was one of many tragedies that were born from humans' hideous desires.","TWN":"感想如何？這就是人類的自私釀成的悲劇。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"넌 그런 모습을 보고도, 아직도 인간들을 위해 싸우고 싶은 거니?","JPN":"貴様はそんなものを見ても、まだ人間のために戦いたいか？","ENG":"Do you still want to fight for humans, after watching this?","TWN":"你看完還會想爲人類而戰嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"당신은…… 이 기억에서 비극과 인간의 추악한 면을 보았군요.","JPN":"あなたは……この記憶から悲劇と人間の醜悪さを見たのですね。","ENG":"You saw... a tragedy and the ugly side of us humans from this memory.","TWN":"你……在這段記憶中，看到的是悲劇和人性的醜惡一面。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하지만 인간에겐 그런 이기심만 있는 게 아닙니다.","JPN":"ですが、人間にはそのような利己主義しかないわけではありません。","ENG":"But we’re more than that.","TWN":"但人類並不是只有自私的一面。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"전 이 기억으로부터 희망을 보았어요.","JPN":"私はこの記憶から希望を見つけました。","ENG":"I saw a hope from this.","TWN":"我從這個記憶中看到的是希望。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"……희망?","JPN":"……希望？","ENG":"A hope?","TWN":"……希望？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"아하핫!","JPN":"アハハッ！","ENG":"Ah hah hah!","TWN":"哈哈哈！"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"거기엔 배신과 술수 뿐이야.","JPN":"そこには裏切りと謀略があるだけだ。","ENG":"There was nothing but a betrayal and a scheme.","TWN":"裡面只有背叛和心機而已。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"무사는 당주를 빼돌리려다 결국 제 손으로 죽였고, 음모는 결국 밝혀지지 못했지.","JPN":"武士は当主を逃がそうとしたが結局自分の手で殺め、\\n陰謀は最後まで明らかになることはなかった。","ENG":"The bodyguard tried to hide her Lady away, but had to kill her with her own hands; the scheme never came to light.","TWN":"武士帶走堂主後，結果還是親手殺掉堂主，詭計也始終無法揭穿。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"게다가 이 모든 사건을 일으킨 녀석은 마지막 순간 날 저주하면서 죽었단다.","JPN":"しかも、この一連の事件を起こしたやつは、\\n最期の瞬間に私を呪いながら死んだのだ。","ENG":"And the culprit behind all this died, cursing my name.","TWN":"而惹出這一切事端的傢伙，臨死前還在詛咒我。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"그 안에 희망 같은 건 없어.","JPN":"その中に希望などない。","ENG":"There is no hope in this.","TWN":"那裡面沒有希望。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"아뇨.","JPN":"いいえ。","ENG":"You’re wrong.","TWN":"不。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하야미 가문은…… 배신을 하지 않았어요.","JPN":"速水家は……裏切りをしませんでした。","ENG":"Hayami never faltered.","TWN":"速水家族……不是叛徒。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"끝까지, 소중한 사람을 위해 굴하지 않고 저항했죠.","JPN":"最後まで、大切な人のために屈せず抵抗しました。","ENG":"She fought until the end to protect someone she cared for.","TWN":"她直到最後都沒有屈服，誓死抵抗要保護最在意的人。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"무녀와 호위 무사.","JPN":"巫女と護衛。","ENG":"The priestess and the bodyguard.","TWN":"巫女和護衛武士，"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"두 사람은 마지막까지 인간으로서의 긍지를 잃지 않았던 겁니다.","JPN":"二人は最後まで、人間としての誇りを失わなかったのです。","ENG":"They never lost their human dignity until the very last moment.","TWN":"她們直到最後一刻，都沒有失去身為一個人的驕傲。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"너희가 말하는 긍지가 고작 죽음이라니, 딱하구나.","JPN":"貴様らの言う誇りがただの死だとは気の毒だな。","ENG":"You find dignity in death. What a pity.","TWN":"驕傲的結果就是死，真可憐。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"좋다.","JPN":"よかろう。","ENG":"Very well.","TWN":"好吧。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"네가 원한 것이 그런 것이라면, 그 긍지를 이룰 수 있도록 내가 거들어주마.","JPN":"貴様の望みがそれであれば、その誇りを守れるように我が手伝ってやろう。","ENG":"If that’s what you wish, I’ll grant you the dignity.","TWN":"若那是你想要的，我就成全你的驕傲吧！"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"이제 끝이다!","JPN":"これで仕舞いだ！","ENG":"Let’s end this all!","TWN":"都結束了！"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"흥, 귀찮군. 아직도 막아낼 기운이……?","JPN":"ふん、面倒だな。まだ防げる力が……？","ENG":"Hmpf, how bothersome. You still have the power to fight back...","TWN":"哼，真煩！還沒放棄抵抗嗎……？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"뭐야. 너……","JPN":"どういうことだ、貴様……","ENG":"What? You...","TWN":"搞什麼，你……"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"그럴 리가……","JPN":"そんなはずは……","ENG":"It cannot be...","TWN":"怎麼可能……"},"stage":{"bg":"NANAHARA_04","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"너 같은 평범한 인간이 어째서……","JPN":"貴様のような平凡な人間がなぜ……","ENG":"You’re just a human...","TWN":"像你這種平凡的人……"},"stage":{"bg":"NANAHARA_04","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"천총운검의 신력을 발현할 수 있는 거지?!","JPN":"天叢雲剣の神力を発現できる！？","ENG":"Yet you’re using the power of Kusanagi?!","TWN":"怎麼可能發現天叢雲劍的神力？！"},"stage":{"bg":"NANAHARA_04","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"오로치여.","JPN":"オロチよ。","ENG":"Orochi.","TWN":"大蛇。"},"stage":{"bg":"NANAHARA_04","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저는, 바람이 들려주었던 미래가 마지막 희망이라고 생각했습니다.","JPN":"私は、風が聞かせてくれた未来が最後の希望だと思っていました。","ENG":"When I heard the future that the wind whispered to me, I thought it was the only hope we had.","TWN":"我以前認爲風聲告訴我的的未來是最後的希望。"},"stage":{"bg":"NANAHARA_04","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하지만 지금은 알고 있어요.","JPN":"ですが、今は知っています。","ENG":"But now I know.","TWN":"但我現在知道，"},"stage":{"bg":"NANAHARA_04","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"바람은 방향만을 가르쳐 줄 뿐, 때로 우리는 그 바람을 거슬러야 할 때도 있다는 것을요.","JPN":"風は方向だけを告げてくれるだけで、時に私たちはその風に\\n逆らわなければならない時もあるということを。","ENG":"The wind only gives me direction; sometimes I have to go against it.","TWN":"風只能指引方向，有時我們也需要逆風而行。"},"stage":{"bg":"NANAHARA_04","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그대는 상처받았습니다.","JPN":"貴方は傷ついたのでしょう。","ENG":"You were hurt by humans.","TWN":"你受傷了。"},"stage":{"bg":"NANAHARA_04","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"믿었던 인간들의 욕망에, 신뢰의 배반에 좌절했겠죠.","JPN":"信じていた人間の欲望に、信頼への裏切りに絶望したのでしょう。","ENG":"You trusted them, but they betrayed you due to their selfish desires.","TWN":"因為人類的慾望和背叛而受挫。"},"stage":{"bg":"NANAHARA_04","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그런 그대가 무녀의 몸을 취한 뒤, 바람의 목소리로부터 어떤 미래를 들었는지는 모르겠지만,","JPN":"そんな貴方が巫女の身体を手に入れた後、\\n風の声からどのような未来を聞いたのかはわかりませんが。","ENG":"I don’t know what you heard from the voice of wind after you took over the priestess’s body.","TWN":"雖然我不知道你奪取巫女的身體後，從風聲中聽到什麼樣的未來，"},"stage":{"bg":"NANAHARA_04","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저는 더 이상 바람의 목소리에만 기대지 않겠습니다.","JPN":"私はこれ以上、風の声だけを頼りにすることはしません。","ENG":"But I will no longer lean on the voice of wind.","TWN":"但我決定不再依靠風聲。"},"stage":{"bg":"NANAHARA_04","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"인간을 지켜야 할 존재가 인간을 능멸하는 순간, 그대의 역할은 끝난 것입니다.","JPN":"人間を守るべき存在が人間を軽蔑した時、貴方の役割は終わったのです。","ENG":"You were supposed to protect humans. When you decided to go against humans, you lost your place in this world.","TWN":"你原本是該守護人類的，但在你輕蔑人類的瞬間，你便已經失去作用。"},"stage":{"bg":"NANAHARA_04","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"……아니야.","JPN":"……違う。","ENG":"No.","TWN":"……不。"},"stage":{"bg":"NANAHARA_04","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"이대로 당하진 않겠어!","JPN":"このままやられるわけにはいかぬ！","ENG":"I won’t go down like this!","TWN":"我一定會反擊的！"},"stage":{"bg":"NANAHARA_04","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_THUNDER"},{"id":"L42_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_04","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"이럴 수가…… 전혀 통하지 않는다고?","JPN":"なんだと……まったく通じない？","ENG":"No way... It doesn’t work at all?","TWN":"怎麼可能……完全無效？"},"stage":{"bg":"NANAHARA_04","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"두려워 마십시오. 그대는 단지 태고의 존재로 돌아갈 뿐입니다.","JPN":"怖がらないでください。貴方はただ、太古の存在に戻るだけです。","ENG":"Don’t be afraid. You will only return to your original form.","TWN":"不要害怕，你只是打回原形而已。"},"stage":{"bg":"NANAHARA_04","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"세상이 그대를 필요로 한다면, 먼 훗날 다시 깨어나게 되겠지요.","JPN":"世界が貴方を必要とするならば、いつかまた目覚めることになるでしょう。","ENG":"When the world calls upon you, you will come back.","TWN":"如果世界需要你，在遙遠的未來你便會甦醒。"},"stage":{"bg":"NANAHARA_04","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"……안 돼.","JPN":"……ならぬ。","ENG":"No...","TWN":"……不可以！"},"stage":{"bg":"NANAHARA_04","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"난 인간들에게 복수해야 한단 말이다!","JPN":"我は人間どもに復讐をせねばならぬのだ！","ENG":"I have to take my revenge!","TWN":"我會向人類報仇！"},"stage":{"bg":"NANAHARA_04","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"뭐야.","JPN":"なんだ。","ENG":"What?","TWN":"搞什麼？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"방금 무슨 일이 일어난 거지?","JPN":"今何が起きた？","ENG":"What just happened?","TWN":"剛剛發生什麼事？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"끄응……","JPN":"ぐうっ……","ENG":"Urgh...","TWN":"唔……"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"뭐야…… 나, 살아있었나?","JPN":"なんだ……オレ、生きてたのか？","ENG":"I’m still alive?","TWN":"怎麼搞的……我還活著嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"사나에! 치후유! 괜찮은 거야?","JPN":"早苗！　千冬！　大丈夫か？","ENG":"Sanae! Chifuyu! Are you alright?","TWN":"早苗！千冬！你們沒事吧？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"아무래도 그런 것 같습니다.","JPN":"……どうやらそのようです。","ENG":"I think so.","TWN":"應該沒事。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"마사키 공…… 살아 계셨군요.","JPN":"雅紀殿……ご無事でしたか。","ENG":"Mr. Katori... You’re alive.","TWN":"雅紀……你還活著。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그, 그러게. 눈앞이 번쩍하면서 끝난 줄 알았는데, 지금은 한숨 잔 것처럼 멀쩡해.","JPN":"そ、そうだな。目の前が光ってこれで終わりかと思ったけど、\\n今はたっぷり寝た後みたいに元気だ。","ENG":"Yeah, I thought I was dead when I saw the lightning in front of my eyes. But now I feel so refreshed.","TWN":"對啊，我眼前閃過那道光的時候，我以為我死定了，現在感覺好像只是睡了一覺一樣。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"제가 입었던 상처도…… 아물었군요.","JPN":"私が負った傷も……治っています。","ENG":"My wounds are all healed, too.","TWN":"我受的傷……也癒合了。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"아니, 오히려 이전보다 더 강해진 느낌입니다.","JPN":"いいえ、むしろ以前よりも力が増した気がします。","ENG":"I even feel stronger than before.","TWN":"不，感覺似乎比以前更強。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하지만 어떻게……?","JPN":"しかし、なぜ……？","ENG":"But how?","TWN":"可是，怎麼會……？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"아하하하하하!!!","JPN":"アハハハハハハハッ！！","ENG":"Ah hah hah hah!","TWN":"哈哈哈哈哈！！！"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"기껏 얻어낸 신력으로 무얼 하려나 했더니…","JPN":"せっかく得た神力で何をするかと思えば……","ENG":"I was wondering what you were going to do with the divine power you gained...","TWN":"我還想你會用好不容易得到的神力做什麼…"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"고작 이깟 미물들을 살려내는데 신력을 쏟아부었다고?","JPN":"こんな虫けら同然の人間どもを生かすために神力を注ぎ込んだだと？","ENG":"And you used it to save these insignificant critters?","TWN":"結果是把神力全部用在救他們嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"후훗, 자신의 목숨까지 바치려 했던 무녀가 이런 어리석은 선택을 할 줄이야.","JPN":"ふふっ、己の命まで捧げようとした巫女が、こうも愚かな選択をするとは。","ENG":"Hah hah, who would have known that the priestess who was willing to sacrifice her own life would make such a foolish choice?","TWN":"呵呵，沒想到原本想獻出自己生命的巫女，會做出這種愚昧的選擇。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"아니. 치나츠는 잘못된 선택을 하지 않았어.","JPN":"いや、千夏は選択を間違えてなんかない。","ENG":"No, Chinatsu made the right choice.","TWN":"不，千夏沒有做出錯誤的選擇。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"뭣이?","JPN":"何？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"당신은 반드시……","JPN":"お前は必ず……","ENG":"Because...","TWN":"我一定會……"},"stage":{"bg":"NANAHARA_01","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"내가 쓰러뜨리기로. 약속했으니까!","JPN":"僕が倒すと、約束したから！","ENG":"I promised her that I would slay you!","TWN":"打倒你！打勾勾！"},"stage":{"bg":"NANAHARA_01","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_09"},{"id":"L33_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"흥, 나유카 가문의 존속이여.","JPN":"ふん、奈由香家の子息よ。","ENG":"You, the remnant of the Nayuka family.","TWN":"哼，南裕夏家族的後裔，"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"너는 크나큰 착각을 하고 있구나.","JPN":"貴様は大きな勘違いをしているぞ。","ENG":"You’re making a grave mistake.","TWN":"你好像有很大的誤解。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"그래, 네가 정말 네 선조처럼 별을 떨어트릴 수 있다면 날 쓰러트릴 수도 있겠지.","JPN":"貴様が本当に先祖のように星を落とすことができるのなら、\\n我を倒すこともできよう。","ENG":"Yes, you might slay me if you could shoot down a star like your ancestor did.","TWN":"沒錯，若你能像你的祖先一樣射下星星，那你或許能打倒我。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"하지만 그땐 하야미 가문의 무사가 내 발을 묶어 두고 함께 희생했기에 가능한 일이었다.","JPN":"だが、あの時は速水家の武士が我を足止めし、\\n諸共犠牲になったからこそ可能なことだった。","ENG":"But back then, they succeeded only because a Hayami warrior hindered me by sacrificing herself.","TWN":"但當時是速水家族的武士拖著我一起犧牲，才會發生那種事。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"그것은 수많은 인간 놈들의 희생이 아귀가 맞물려 벌어질 수 있었던 우연의 산물이었지.","JPN":"それは多くの人間どもの犠牲が重なり合って起きた、偶然の産物だった。","ENG":"It was just a coincidence that resulted from countless sacrifices.","TWN":"那是許多人類一起通力合作，甚至是犧牲才產生的巧合。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"그런데 연합이 서로를 배반하기 바쁜 지금에 와서……","JPN":"なのに、連合が忙しなく互いを裏切る今……","ENG":"But now the Alliance has turned against each other...","TWN":"但是聯盟現在忙著搞內鬨……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"예전과 같은 일이 일어날 수 있을 거라 생각하느냐?","JPN":"かつてのようなことが起こり得ると思うか？","ENG":"Do you think you’ll have the luxury of such a coincidence again?","TWN":"你認爲還會發生像以前那樣的事嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"물론 있지.","JPN":"無論ある。","ENG":"Aye, I do.","TWN":"當然會。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_MASKED","text":{"KOREA":"만나보고 싶었다, 오로치.","JPN":"会いたかったぞ、オロチ。","ENG":"I have long waited for this day, Orochi.","TWN":"我很想念你呢，大蛇。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_MASKED","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"하야미……? 아니야, 넌……","JPN":"速水……？　いや、貴様は……","ENG":"Hayami? No, you’re...","TWN":"速水……？不對，你……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_MASKED","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"넌 이미 죽었을 텐데? 어떻게 살아있는 거지?!","JPN":"貴様は死んだはずだが？　どうして生きておる！？","ENG":"You already died. How are you still alive?","TWN":"你應該已經死了？怎麼會還活著？！"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"살아있지 않아.","JPN":"生きてはいない。","ENG":"I am not alive.","TWN":"我是死的沒錯。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"저승길을 잠시 거슬러왔을 뿐이란다.","JPN":"少しの間、三途の川を遡ってきただけだ。","ENG":"I came back from the dead only for a short while.","TWN":"我只是暫時回到現世而已，"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"네 발을 붙잡기 위해서 말이야.","JPN":"貴様を足止めするためにな。","ENG":"To stop you.","TWN":"為的是要抓住你。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"잠깐, 그 가면은 설마……!","JPN":"待て、その面はまさか……！","ENG":"Wait, that mask...","TWN":"等一下，那個面具該不會……！"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"생명을 비롯한 모든 물건에는 작게나마 혼이 깃든 채로 태어납니다.","JPN":"生命をはじめ、あらゆるモノはわずかでも必ず魂を宿して生まれます。","ENG":"Everything in the world has a soul, however small it may be.","TWN":"包括生命在內的一切，都是有靈魂的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"활과 같은 도구 또한 마찬가지.","JPN":"弓のような道具も同じです。","ENG":"So do tools, like this bow.","TWN":"像是弓箭這類的工具也是一樣。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"오래된 물건일수록 그것의 혼은 사용자의 사념을 품은 형태로 성장하게 되죠.","JPN":"古いモノほど、その魂は持ち主の思念を抱き、成長するのです。","ENG":"When an item grows old, its soul begins to bear the will of its owner.","TWN":"越是古老的東西，裡面的靈魂就會照著使用者的思念成長。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저는 그 사념의 귀를 열어 부탁할 뿐이랍니다.","JPN":"私はその思念に耳を傾けて、願っただけですよ。","ENG":"All I do is ask for the will to help.","TWN":"我只是打開思念的耳朵拜託它而已。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……사념?","JPN":"……思念？","ENG":"The lingering will?","TWN":"……思念？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"가면에 깃든 사념을…… 신력으로 실체를 만들었다고?!","JPN":"面に宿った思念を……神力で実体を作ったのか！？","ENG":"The will within the mask was materialized by divine power?","TWN":"神力讓面具上的思念……化作實體？！"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"그건 불가능해! 본래의 육신을 이곳에 묻어둔 게 아닌 이상에야……!","JPN":"それは不可能だ！\\n本来の肉体をここに埋めておいたのでもない以上……！","ENG":"That’s impossible, unless your body is buried here...","TWN":"那是不可能的！除非把原本的軀體埋在這裡…！"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"……설마?","JPN":"……まさか？","ENG":"Wait, could it be...","TWN":"……難道？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"사요, 그 멍청한 것이……!","JPN":"小夜、あの愚か者め……！","ENG":"Sayo, that fool!","TWN":"小夜，那個蠢東西……！"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"봉인명주 27타래.","JPN":"封印絹糸二十七束。","ENG":"The 27 Silk Threads of Sealing.","TWN":"封印珠27條。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"이걸로 너와 내가 빠져나갈 구멍은 없다.","JPN":"これで貴様と私の逃げ道はない。","ENG":"Now, there is no escape for us.","TWN":"這樣你和我都沒得逃。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"나와 함께 나락으로 떨어지자꾸나.","JPN":"私と共に奈落に落ちよ。","ENG":"Thou wilt come with me to hell.","TWN":"和我一起下地獄吧。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"이……","JPN":"この……","ENG":"You...","TWN":"這……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"이 하찮은 망령 주제에!!!","JPN":"つまらぬ亡霊ごときが！！！","ENG":"You’re only a wraith!","TWN":"該死的鬼魂！！！"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"오로치.","JPN":"オロチ。","ENG":"Orochi.","TWN":" 大蛇。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"사람이 더럽혀지기 전에 삶을 거두어 간다고 했지?","JPN":"人が穢れる前に命を奪ってやると言ったよな？","ENG":"You said you were going to take our lives before we became corrupted.","TWN":"你不是說過，要到受到污染前結束人生嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"너……","JPN":"貴様……！","ENG":"You...","TWN":"你……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"나유카 미나토!","JPN":"奈由香湊！","ENG":"Nayuka Minato!","TWN":"南裕夏！"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"하지만 모든 인간이 깨끗하지 못하다고 해서, 인간의 남은 희망마저 부정할 순 없어.","JPN":"だけど、すべての人間が綺麗じゃないからといって、\\n人間が残した希望まで否定することはできない。","ENG":"Some people are corrupted; that’s true. But you can’t deny hope from everyone just because of them.","TWN":"但是不能因爲所有的人都不潔淨，就否定人類留下的希望。"},"stage":{"bg":"NANAHARA_02","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"당신은 인간들과 다르고, 강하며, 인간의 모든 내면을 꿰뚫고 있다고 생각했겠지만……","JPN":"お前は人間と違い、強く、人間のあらゆる内心を見抜いていると思っていたんだろうけど……","ENG":"You might have thought that you were different from us, stronger than us, and know everything about us...","TWN":"你可能以爲你和人類不同，你很強，又能看透人心……"},"stage":{"bg":"NANAHARA_02","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"당신이야말로 상처입고 병들었을 뿐인, 여느 인간과 다름없는 연약한 존재야.","JPN":"お前こそ傷つき病にかかっただけの、普通の人間と変わらない弱い存在だ。","ENG":"But you are actually as fragile as us, wounded and sick.","TWN":"但其實你和人類一樣脆弱，一樣會受傷，一樣會生病。"},"stage":{"bg":"NANAHARA_02","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"자신의 복수를 행하고, 그 뒤에 그럴싸한 이유를 붙일 뿐인, 그런 평범한 악인이었을 뿐이지.","JPN":"自分の復讐を行い、その後にもっともらしい理由をつけただけの、\\nそんな平凡な悪人にすぎない。","ENG":"You’re a plain villain who is only trying to justify your revenge.","TWN":"你只是替自己的行為找到一個看似合理藉口的壞人。"},"stage":{"bg":"NANAHARA_02","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그러니……","JPN":"だから……","ENG":"Now...","TWN":"所以……"},"stage":{"bg":"NANAHARA_01","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"이제 빼앗긴 일상을 돌려받겠어!","JPN":"奪われた僕の日常を返してもらう！","ENG":"Give us back our everyday lives!","TWN":"我要找回被奪走的平凡生活！"},"stage":{"bg":"NANAHARA_01","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"아아……","JPN":"ああ……","ENG":"Ah...","TWN":"啊啊……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"사람은…… 우리처럼 천수를 누리지 못해.","JPN":"人は……私たちのように永遠を生きることはできない。","ENG":"Humans don’t live forever, like us.","TWN":"人…… 無法像我們一樣享有天壽。"},"stage":{"bg":"BLACK","bgm":"THEMA_NANAHARA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"짧은 삶을 살기 때문에, 처음부터 실수와 후회를 반복하며 성장한단다.","JPN":"短い人生を送るため、生まれてからずっと\\n過ちと後悔を繰り返しながら成長するもの。","ENG":"They have short lives. They grow up by repeating mistakes and regrets.","TWN":"因爲生命很短暫，所以一出生就在不斷的犯錯和後悔中成長。"},"stage":{"bg":"BLACK","bgm":"THEMA_NANAHARA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니…… 부디.","JPN":"だから……どうか。","ENG":"So please...","TWN":"所以……千萬，"},"stage":{"bg":"BLACK","bgm":"THEMA_NANAHARA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"나의 죽음으로 인해 인간을 미워하지 말아다오, 오로치.","JPN":"私の死のせいで人間を憎まないで、オロチ。","ENG":"Do not hate them for my death, Orochi.","TWN":"不要因爲我的死而討厭人類， 大蛇。"},"stage":{"bg":"BLACK","bgm":"THEMA_NANAHARA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"……무녀님.","JPN":"……巫女様。","ENG":"... Priestess.","TWN":"……巫女大人。"},"stage":{"bg":"BLACK","bgm":"THEMA_NANAHARA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_COFFIN_LASER_MAIN_EXPLOSION"}]`);export{e as default};